/**
 * MedX drawer-layout layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Slide-over drawer layout slots.
 */
const DRAWER_LAYOUT_TOKENS = Object.freeze({
  primary: { value: "layout-drawer-layout-primary", scope: "layout" },
  secondary: { value: "layout-drawer-layout-secondary", scope: "layout" },
  muted: { value: "layout-drawer-layout-muted", scope: "layout" },
  accent: { value: "layout-drawer-layout-accent", scope: "layout" },
  surface: { value: "layout-drawer-layout-surface", scope: "layout" },
});

const DRAWER_LAYOUT_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const DRAWER_LAYOUT_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const drawerlayoutRegistry = new Map();
const DRAWER_LAYOUT_listeners = new Set();
let DRAWER_LAYOUT_seq = 0;

function createDrawerLayoutId(prefix = "medx-layout-drawer-layout") {
  DRAWER_LAYOUT_seq += 1;
  return `${prefix}-${DRAWER_LAYOUT_seq}`;
}

function registerDrawerLayout(config = {}) {
  const entryId = config.id ?? createDrawerLayoutId();
  const preset = DRAWER_LAYOUT_PRESETS[config.preset ?? "default"] ?? DRAWER_LAYOUT_PRESETS.default;
  const token = DRAWER_LAYOUT_TOKENS[config.token ?? preset.token] ?? DRAWER_LAYOUT_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: DRAWER_LAYOUT_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  drawerlayoutRegistry.set(entryId, entry);
  notifyDrawerLayoutListeners("register", entry);
  return entry;
}

function updateDrawerLayout(id, patch = {}) {
  const entry = drawerlayoutRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyDrawerLayoutListeners("update", entry);
  return entry;
}

function resolveDrawerLayout(id) {
  const entry = drawerlayoutRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listDrawerLayoutEntries(filter = {}) {
  let items = Array.from(drawerlayoutRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onDrawerLayoutEvent(listener) {
  DRAWER_LAYOUT_listeners.add(listener);
  return () => DRAWER_LAYOUT_listeners.delete(listener);
}

function notifyDrawerLayoutListeners(type, entry) {
  for (const listener of DRAWER_LAYOUT_listeners) {
    try {
      listener({ type, entry, registrySize: drawerlayoutRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:drawer-layout] listener error", err.message);
    }
  }
}

function getDrawerLayoutMetrics() {
  const items = listDrawerLayoutEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(DRAWER_LAYOUT_TOKENS).length,
    presets: Object.keys(DRAWER_LAYOUT_PRESETS).length,
  };
}

async function runMedxDrawerLayout() {
  console.log("[medx:ui:layout:drawer-layout] runtime initialized");
  console.log(`[medx:ui:layout:drawer-layout] tokens=${Object.keys(DRAWER_LAYOUT_TOKENS).length} presets=${Object.keys(DRAWER_LAYOUT_PRESETS).length}`);

  const events = [];
  onDrawerLayoutEvent((e) => events.push(e.type));

  const domains = Object.keys(DRAWER_LAYOUT_SUPPLY_CHAIN);
  const presets = Object.keys(DRAWER_LAYOUT_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerDrawerLayout({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/drawer-layout" },
    });
  }

  const first = listDrawerLayoutEntries()[0];
  if (first) updateDrawerLayout(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getDrawerLayoutMetrics();
  const resolved = first ? resolveDrawerLayout(first.id) : null;

  console.log(`[medx:ui:layout:drawer-layout] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:drawer-layout] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:drawer-layout] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:drawer-layout] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:drawer-layout] bootstrap complete");
}

module.exports = runMedxDrawerLayout;
